-- Import work sections and items from Excel
BEGIN;

-- Insert distinct sections if not exist
INSERT INTO work_sections (name)
SELECT DISTINCT section_name FROM (VALUES 
  ('اعمال التراخيص'),  ('اعمال التصميم'),  ('اعمال الخرسانات'),  ('التشطيبات')
) AS t(section_name)
WHERE NOT EXISTS (
  SELECT 1 FROM work_sections ws WHERE ws.name = t.section_name
);

-- Insert items linked to sections
INSERT INTO work_items (section_id, section_name, name)
SELECT ws.id, ws.name, item_name
FROM (VALUES 
  ('اعمال التراخيص', 'اعمال التراخيص'),  ('اعمال التراخيص', 'اعمال التراخيص'),  ('اعمال التصميم', 'اعمال التصميم'),  ('اعمال الخرسانات', 'اعمال الحديد'),  ('اعمال الخرسانات', 'اعمال الكهرباء(خ)'),  ('اعمال الخرسانات', 'اعمال النقاشة(خ)'),  ('اعمال الخرسانات', 'اعمال البناء'),  ('اعمال الخرسانات', 'اعمال الحديد'),  ('اعمال الخرسانات', 'اعمال النجارة المسلحة'),  ('التشطيبات', 'اخرى'),  ('التشطيبات', 'اعمال curtain wall'),  ('التشطيبات', 'اعمال الارضيات'),  ('التشطيبات', 'اعمال الارضيات(خ)'),  ('التشطيبات', 'اعمال الارضيات(م)'),  ('التشطيبات', 'اعمال الاسانسير'),  ('التشطيبات', 'اعمال الاستور'),  ('التشطيبات', 'اعمال البناء'),  ('التشطيبات', 'اعمال البناء (خ)'),  ('التشطيبات', 'اعمال البناء (م)'),  ('التشطيبات', 'اعمال التشوينات'),  ('التشطيبات', 'اعمال التكيفات'),  ('التشطيبات', 'اعمال الجبسون بورد'),  ('التشطيبات', 'اعمال الحديد'),  ('التشطيبات', 'اعمال الرخام'),  ('التشطيبات', 'اعمال السباكة (خ)'),  ('التشطيبات', 'اعمال السباكة (م)'),  ('التشطيبات', 'اعمال الصحي'),  ('التشطيبات', 'اعمال العزل'),  ('التشطيبات', 'اعمال الكهرباء'),  ('التشطيبات', 'اعمال الكهرباء(خ)'),  ('التشطيبات', 'اعمال الكهرباء(م)'),  ('التشطيبات', 'اعمال المحارة'),  ('التشطيبات', 'اعمال المحارة(خ)'),  ('التشطيبات', 'اعمال المحارة(م)'),  ('التشطيبات', 'اعمال النجارة'),  ('التشطيبات', 'اعمال النظافة'),  ('التشطيبات', 'اعمال النقاشة(خ)'),  ('التشطيبات', 'اعمال النقاشة(م)'),  ('التشطيبات', 'اعمال النقل'),  ('التشطيبات', 'اعمال حمام السباحة'),  ('التشطيبات', 'اعمالupvc'),  ('التشطيبات', 'اكراميات'),  ('التشطيبات', 'الفرش'),  ('التشطيبات', 'تشوينات الارضيات (خ)'),  ('التشطيبات', 'تشوينات الارضيات (م)'),  ('التشطيبات', 'يوميات'),  ('التشطيبات', 'اعمال الهدم'),  ('التشطيبات', 'اعمال السقالة'),  ('التشطيبات', 'اعمال الشفاطات'),  ('التشطيبات', 'اعمال الجبس البلدي'),  ('التشطيبات', 'اعمال الحديد(م)'),  ('التشطيبات', 'تشوينات الارضيات'),  ('التشطيبات', 'اعمال التشوينات(خ)'),  ('التشطيبات', 'تشوينات')
) AS t(section_name, item_name)
JOIN work_sections ws ON ws.name = t.section_name;

COMMIT;